const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
if (!secret || secret !== (process.env.INTERNAL_EMAIL_SECRET || '')) return { json: { _unauthorized: true, error: 'internal secret required' } };
if (!body.policy_application_id) return { json: { _empty: true, error: 'policy_application_id required' } };
if (body.total_commission_cents == null) return { json: { _empty: true, error: 'total_commission_cents required (in cents)' } };
return { json: { _authorized: true, policy_application_id: body.policy_application_id, total_commission_cents: parseInt(body.total_commission_cents) || 0, premium_amount_cents: parseInt(body.premium_amount_cents) || 0, policy_number: body.policy_number || null } };

const ctx = $('Validate').item.json;
const rows = $input.item.json;
const app = (Array.isArray(rows) ? rows[0] : rows) || null;
if (!app || !app.id) return { json: { _not_found: true, error: 'policy_application not found' } };
return { json: { app: app, total_commission: ctx.total_commission_cents, premium: ctx.premium_amount_cents, policy_number: ctx.policy_number || app.policy_number } };

const carry = $('Carry App').item.json;
const app = carry.app;
const rows = $input.item.json;
const appt = (Array.isArray(rows) ? rows[0] : rows) || null;
if (!appt || !appt.id) return { json: { _no_appointment: true, error: 'no active carrier_appointments row found for advisor + carrier' } };
const total = carry.total_commission;
const pctC = parseFloat(appt.commission_split_carrier) || 0;
const pctM = parseFloat(appt.commission_split_mga) || 0;
const pctA = parseFloat(appt.commission_split_advisor) || 0;
const carrierC = Math.round(total * pctC / 100);
const mgaC = Math.round(total * pctM / 100);
const advisorC = total - carrierC - mgaC; // residual to advisor for rounding precision
return { json: {
  insert_row: {
    vertical_id: 'insurance',
    policy_application_id: app.id,
    carrier_appointment_id: appt.id,
    advisor_id: app.advisor_id,
    mga_principal_id: appt.mga_principal_id,
    policy_number: carry.policy_number,
    carrier_name: app.carrier_name,
    product_type: app.product_type || null,
    premium_amount: carry.premium,
    total_commission: total,
    carrier_commission: carrierC,
    mga_commission: mgaC,
    advisor_commission: advisorC,
    sub_agent_commission: 0,
    override_commission: 0,
    payout_status: 'pending'
  },
  policy_application_id: app.id,
  advisor_id: app.advisor_id
} };
